#include <bits/stdc++.h>
using namespace std;

const int N=8e6+10;

struct Node{
    int l,p;
}qu[3][N];

int n,m,q,u,v,t,a[N];
int hh[3],tt[3];

int cal(int x,Node val){
    return val.l+(x-val.p)*q;
}

int main(){
    scanf("%d%d%d%d%d%d",&n,&m,&q,&u,&v,&t);
    hh[0]=hh[1]=hh[2]=1;
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    sort(a+1,a+n+1,greater<int>());
    for(int i=1;i<=n;i++)
        qu[0][++tt[0]]={a[i],0};
    for(int i=1;i<=m;i++){
        int res=-1,p;
        if(hh[0]<=tt[0] && res<cal(i-1,qu[0][hh[0]]))
            res=cal(i-1,qu[0][hh[0]]),p=0;
        if(hh[1]<=tt[1] && res<cal(i-1,qu[1][hh[1]]))
            res=cal(i-1,qu[1][hh[1]]),p=1;
        if(hh[2]<=tt[2] && res<cal(i-1,qu[2][hh[2]]))
            res=cal(i-1,qu[2][hh[2]]),p=2;
        hh[p]++;
        if(i%t==0)
            printf("%d ",res);
        qu[1][++tt[1]]={1ll*res*u/v,i};
        qu[2][++tt[2]]={res-1ll*res*u/v,i};
    }
    puts("");
    for(int i=1;i<=n+m;i++){
        int res=-1,p;
        if(hh[0]<=tt[0] && res<cal(m,qu[0][hh[0]]))
            res=cal(m,qu[0][hh[0]]),p=0;
        if(hh[1]<=tt[1] && res<cal(m,qu[1][hh[1]]))
            res=cal(m,qu[1][hh[1]]),p=1;
        if(hh[2]<=tt[2] && res<cal(m,qu[2][hh[2]]))
            res=cal(m,qu[2][hh[2]]),p=2;
        hh[p]++;
        if(i%t==0)
            printf("%d ",res);
    }
    return 0;
}
